//------------------------------------------------------
//MRFGrooveSweepInsertDlg::Build
//Function:  Build the Insert DLg
//------------------------------------------------------
void MRFGrooveSweepInsertDlg::Build()
{
	int style = 0;

	_frmMain = new CATDlgFrame(this, (const char*)"MainFrame", 0 | CATDlgGridLayout | CATDlgFraNoFrame);
	_radioBtnCurveRatio = new CATDlgRadioButton(_frmMain, (const char*)" Curve Ratio ", 0);
	_radioBtnCurveDistance = new CATDlgRadioButton(_frmMain, (const char*)" Curve Distance ", 0);
	_spinnerCurveRatio = new CATDlgSpinner(_frmMain, (const char*)"Curve Ratio", 0 | CATDlgSpnDouble | CATDlgSpnEntry);
	_spinnerCurveDistance = new CATDlgSpinner(_frmMain, (const char*)"Curve Distance", 0 | CATDlgSpnDouble | CATDlgSpnEntry);
	_pushBtnInsert = new CATDlgPushButton(_frmMain, (const char*)"  Insert  ", 0 );

	_frmMain->SetGridConstraints(0, 0, 1, 1, 0 | CATGRID_LEFT | CATGRID_RIGHT | CATGRID_TOP | CATGRID_BOTTOM);
	_radioBtnCurveRatio->SetGridConstraints(0, 0, 1, 1, 0 | CATGRID_LEFT | CATGRID_RIGHT | CATGRID_TOP | CATGRID_BOTTOM);
	_spinnerCurveRatio->SetGridConstraints(0, 1, 1, 1, 0 | CATGRID_LEFT | CATGRID_RIGHT | CATGRID_TOP | CATGRID_BOTTOM);
	_radioBtnCurveDistance->SetGridConstraints(1, 0, 1, 1, 0 | CATGRID_LEFT | CATGRID_RIGHT | CATGRID_TOP | CATGRID_BOTTOM);
	_spinnerCurveDistance->SetGridConstraints(1, 1, 1, 1, 0 | CATGRID_LEFT | CATGRID_RIGHT | CATGRID_TOP | CATGRID_BOTTOM);
	_pushBtnInsert->SetGridConstraints(2, 0, 1, 1, 0 | CATGRID_LEFT | CATGRID_RIGHT | CATGRID_TOP | CATGRID_BOTTOM);

	_radioBtnCurveRatio->SetState(CATDlgCheck);
	_spinnerCurveDistance->SetSensitivity(CATDlgDisable);

	_spinnerCurveRatio->SetMinMaxStep(0, 1, 0.1, 1);
	_spinnerCurveDistance->SetMinMaxStep(-10000, 10000, 0.00001, 1);
	//_spinnerCurveRatio->SetUnit(CATDlgControl::CATDlgUnit::Millimeter);
	_spinnerCurveDistance->SetUnit(CATDlgControl::CATDlgUnit::Millimeter);


}

